import React, { useState } from 'react';

// --- 1. Data Interfaces ---
interface Patient {
  id: number;
  first_name: string;
  last_name: string;
  date_of_birth: string;
  gender: string;
  contact_number: string;
  email: string;
}

interface Doctor {
  id: number;
  first_name: string;
  last_name: string;
  specialization: string;
  email: string;
}

interface Appointment {
  id: number;
  patientId: number;
  doctorId: number;
  appointment_date: string;
  status: string;
}

// --- MAIN APP ---
function App() {
  const [activeTab, setActiveTab] = useState<'patients' | 'doctors' | 'appointments'>('patients');
  const [showModal, setShowModal] = useState(false);

  const [patients, setPatients] = useState<Patient[]>([
    { id: 1, first_name: "Alice", last_name: "Smith", date_of_birth: "1990-05-15", gender: "Female", contact_number: "555-0199", email: "alice@email.com" }
  ]);
  const [doctors, setDoctors] = useState<Doctor[]>([
    { id: 1, first_name: "Gregory", last_name: "House", specialization: "Diagnostic Medicine", email: "house@princeton.edu" }
  ]);
  const [appointments, setAppointments] = useState<Appointment[]>([]);

  const [editId, setEditId] = useState<number | null>(null);
  const [formData, setFormData] = useState<any>({});

  const openModal = (item?: any) => {
    if (item) {
      setEditId(item.id);
      setFormData(item);
    } else {
      setEditId(null);
      setFormData({});
    }
    setShowModal(true);
  };

  const handleSave = () => {
    const id = editId || Date.now();
    const dataWithId = { ...formData, id };

    if (activeTab === 'patients') {
      setPatients(editId ? patients.map(p => p.id === editId ? dataWithId : p) : [dataWithId, ...patients]);
    } else if (activeTab === 'doctors') {
      setDoctors(editId ? doctors.map(d => d.id === editId ? dataWithId : d) : [dataWithId, ...doctors]);
    } else if (activeTab === 'appointments') {
      setAppointments(editId ? appointments.map(a => a.id === editId ? dataWithId : a) : [dataWithId, ...appointments]);
    }
    closeModal();
  };

  const deleteItem = (id: number) => {
    if (activeTab === 'patients') setPatients(patients.filter(p => p.id !== id));
    if (activeTab === 'doctors') setDoctors(doctors.filter(d => d.id !== id));
    if (activeTab === 'appointments') setAppointments(appointments.filter(a => a.id !== id));
  };

  const closeModal = () => {
    setShowModal(false);
    setEditId(null);
    setFormData({});
  };

  return (
    <div className="flex min-h-screen bg-[#F8FAFC] text-slate-800 font-sans">
      {/* SIDEBAR - Professional Teal Gradient */}
      <aside className="w-72 bg-gradient-to-b from-[#0D9488] to-[#0F766E] p-8 flex flex-col shadow-xl overflow-hidden relative">
        <div className="mb-10 relative z-10">
          <h1 className="text-2xl font-extrabold text-white tracking-tight flex items-center gap-2">
            <span className="bg-white text-[#0D9488] px-2 py-1 rounded-lg text-xl">+</span> MED-TRAIL
          </h1>
          <p className="text-teal-100 text-xs mt-1 font-medium opacity-80 uppercase tracking-widest">Management System</p>
        </div>

        <nav className="flex flex-col gap-3 relative z-10">
          {(['patients', 'doctors', 'appointments'] as const).map((tab) => (
            <button
              key={tab}
              onClick={() => { setActiveTab(tab); closeModal(); }}
              className={`text-left px-5 py-3.5 rounded-xl font-semibold capitalize transition-all duration-300 flex items-center gap-3 ${
                activeTab === tab 
                ? 'bg-white text-[#0D9488] shadow-lg translate-x-1' 
                : 'text-teal-50 hover:bg-white/10'
              }`}
            >
              <div className={`w-2 h-2 rounded-full ${activeTab === tab ? 'bg-[#0D9488]' : 'bg-teal-300'}`}></div>
              {tab}
            </button>
          ))}
        </nav>

        {/* Decorative circle in sidebar */}
        <div className="absolute -bottom-10 -left-10 w-40 h-40 bg-white/10 rounded-full blur-3xl"></div>
      </aside>

      {/* MAIN VIEW */}
      <main className="flex-1 p-12 overflow-y-auto">
        <header className="flex justify-between items-end mb-12">
          <div>
            <h2 className="text-4xl font-bold text-slate-900 capitalize tracking-tight">
              {activeTab} <span className="text-[#0D9488]">Overview</span>
            </h2>
            <div className="h-1 w-20 bg-[#0D9488] mt-2 rounded-full"></div>
          </div>

          <button 
            onClick={() => openModal()} 
            className="bg-[#0D9488] hover:bg-[#0F766E] text-white px-8 py-3.5 rounded-xl font-bold shadow-lg shadow-teal-200 transition-all flex items-center gap-2 active:scale-95"
          >
            <span className="text-xl">+</span> New Record
          </button>
        </header>

        {/* LISTS - Grid Layout for better use of space */}
        <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
          {activeTab === 'patients' && patients.map(p => (
            <Card key={p.id} title={`${p.first_name} ${p.last_name}`} sub={p.email} info={p.contact_number} tag={p.gender} onEdit={() => openModal(p)} onDelete={() => deleteItem(p.id)} icon="👤" />
          ))}
          {activeTab === 'doctors' && doctors.map(d => (
            <Card key={d.id} title={`Dr. ${d.first_name} ${d.last_name}`} sub={d.specialization} info={d.email} color="border-teal-400" onEdit={() => openModal(d)} onDelete={() => deleteItem(d.id)} icon="🩺" />
          ))}
          {activeTab === 'appointments' && appointments.map(a => {
            const patient = patients.find(p => p.id === Number(a.patientId));
            const doctor = doctors.find(d => d.id === Number(a.doctorId));
            return (
              <Card 
                key={a.id} 
                title={patient ? `${patient.first_name} ${patient.last_name}` : 'Unknown Patient'} 
                sub={`with Dr. ${doctor?.last_name || 'Doctor'}`} 
                info={`📅 ${a.appointment_date}`} 
                tag={a.status} 
                color="border-amber-400" 
                onEdit={() => openModal(a)} 
                onDelete={() => deleteItem(a.id)} 
                icon="📅"
              />
            );
          })}
        </div>

        {/* --- DYNAMIC MODAL - Inspired by your uploaded UI --- */}
        {showModal && (
          <div className="fixed inset-0 bg-slate-900/60 flex items-center justify-center z-50 backdrop-blur-sm p-4">
            <div className="bg-white w-full max-w-xl rounded-[2.5rem] shadow-2xl overflow-hidden border border-slate-100 animate-in fade-in zoom-in duration-300">
              <div className="bg-[#0D9488] p-8 text-white relative">
                <h3 className="text-2xl font-bold capitalize">
                  {editId ? 'Update' : 'Add New'} {activeTab.slice(0, -1)}
                </h3>
                <p className="text-teal-100 text-sm opacity-80">Please fill in the required medical information.</p>
                <div className="absolute top-8 right-8 text-4xl opacity-20">🏥</div>
              </div>

              <div className="p-10">
                <div className="grid grid-cols-1 md:grid-cols-2 gap-5 mb-8">
                  {activeTab === 'patients' && (
                    <>
                      <Input label="First Name" value={formData.first_name} onChange={(v: string) => setFormData({...formData, first_name: v})} />
                      <Input label="Last Name" value={formData.last_name} onChange={(v: string) => setFormData({...formData, last_name: v})} />
                      <Input label="Date of Birth" type="date" value={formData.date_of_birth} onChange={(v: string) => setFormData({...formData, date_of_birth: v})} />
                      <Input label="Gender" placeholder="Male/Female" value={formData.gender} onChange={(v: string) => setFormData({...formData, gender: v})} />
                      <Input label="Contact Number" value={formData.contact_number} onChange={(v: string) => setFormData({...formData, contact_number: v})} />
                      <Input label="Email Address" value={formData.email} onChange={(v: string) => setFormData({...formData, email: v})} />
                    </>
                  )}
                  {activeTab === 'doctors' && (
                    <>
                      <Input label="First Name" value={formData.first_name} onChange={(v: string) => setFormData({...formData, first_name: v})} />
                      <Input label="Last Name" value={formData.last_name} onChange={(v: string) => setFormData({...formData, last_name: v})} />
                      <div className="col-span-2">
                        <Input label="Specialization" value={formData.specialization} onChange={(v: string) => setFormData({...formData, specialization: v})} />
                      </div>
                      <div className="col-span-2">
                        <Input label="Email Address" value={formData.email} onChange={(v: string) => setFormData({...formData, email: v})} />
                      </div>
                    </>
                  )}
                  {activeTab === 'appointments' && (
                    <div className="col-span-2 space-y-5">
                      <Select label="Select Patient" value={formData.patientId} options={patients.map(p => ({label: `${p.first_name} ${p.last_name}`, value: p.id}))} onChange={(v: string) => setFormData({...formData, patientId: v})} />
                      <Select label="Assign Doctor" value={formData.doctorId} options={doctors.map(d => ({label: `Dr. ${d.first_name} ${d.last_name}`, value: d.id}))} onChange={(v: string) => setFormData({...formData, doctorId: v})} />
                      <Input label="Appointment Schedule" type="datetime-local" value={formData.appointment_date} onChange={(v: string) => setFormData({...formData, appointment_date: v})} />
                      <Input label="Status" placeholder="e.g. Scheduled, Completed" value={formData.status} onChange={(v: string) => setFormData({...formData, status: v})} />
                    </div>
                  )}
                </div>

                <div className="flex gap-4">
                  <button onClick={handleSave} className="flex-1 bg-[#0D9488] hover:bg-[#0F766E] text-white py-4 rounded-2xl font-bold text-lg shadow-lg transition-all active:scale-95">
                    Save Record
                  </button>
                  <button onClick={closeModal} className="px-8 bg-slate-100 hover:bg-slate-200 text-slate-500 py-4 rounded-2xl font-bold transition-all">
                    Cancel
                  </button>
                </div>
              </div>
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

// --- SUB-COMPONENTS ---

const Card = ({ title, sub, info, onEdit, onDelete, color = "border-[#0D9488]", tag, icon }: any) => (
  <div className={`bg-white p-6 rounded-3xl border-l-8 ${color} shadow-sm hover:shadow-md transition-all duration-300 group`}>
    <div className="flex justify-between items-start">
      <div className="flex gap-4">
        <div className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center text-2xl group-hover:scale-110 transition-transform">
          {icon}
        </div>
        <div>
          <div className="flex items-center gap-3 mb-1">
            <h4 className="text-xl font-bold text-slate-800">{title}</h4>
            {tag && <span className="bg-teal-50 text-[#0D9488] text-[10px] px-2.5 py-1 rounded-full font-bold uppercase tracking-wider border border-teal-100">{tag}</span>}
          </div>
          <p className="text-[#0D9488] font-medium text-sm">{sub}</p>
          <p className="text-slate-400 text-xs mt-2 font-mono">{info}</p>
        </div>
      </div>
      <div className="flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
        <button onClick={onEdit} className="text-slate-400 hover:text-[#0D9488] text-xs font-bold uppercase p-1">Edit</button>
        <button onClick={onDelete} className="text-slate-400 hover:text-red-500 text-xs font-bold uppercase p-1">Delete</button>
      </div>
    </div>
  </div>
);

const Input = ({ label, type = "text", value, onChange, placeholder }: any) => (
  <div className="flex flex-col gap-1.5">
    <label className="text-xs font-bold text-slate-500 uppercase ml-1 tracking-wide">{label}</label>
    <input 
      type={type} 
      placeholder={placeholder}
      className="w-full p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-[#0D9488] focus:bg-white outline-none font-semibold text-slate-700 transition-all" 
      value={value || ''} 
      onChange={e => onChange(e.target.value)} 
    />
  </div>
);

const Select = ({ label, value, options, onChange }: any) => (
  <div className="flex flex-col gap-1.5">
    <label className="text-xs font-bold text-slate-500 uppercase ml-1 tracking-wide">{label}</label>
    <select 
      className="w-full p-4 bg-slate-50 rounded-2xl border-2 border-transparent focus:border-[#0D9488] focus:bg-white outline-none font-semibold text-slate-700 transition-all appearance-none" 
      value={value || ''} 
      onChange={e => onChange(e.target.value)}
    >
      <option value="">Choose an option...</option>
      {options.map((opt: any) => <option key={opt.value} value={opt.value}>{opt.label}</option>)}
    </select>
  </div>
);

export default App;
